USE P21;
SET NOCOUNT ON;
SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
DECLARE @Target int=682,@Good int=681,@Loc decimal(19,0)=210;
DROP TABLE IF EXISTS #scope; CREATE TABLE #scope(sample_name varchar(20), crh_uid int); INSERT #scope VALUES('TARGET',@Target),('KNOWN_GOOD',@Good);
;WITH lines AS (
 SELECT s.sample_name, crl.container_receipts_hdr_uid, crl.container_receipts_line_uid, crl.complete_po_line_flag, pol.inv_mast_uid, im.item_id, crl.qty_received
 FROM #scope s JOIN container_receipts_line crl ON crl.container_receipts_hdr_uid=s.crh_uid JOIN vessel_receipts_line vl ON vl.vessel_receipts_line_uid=crl.vessel_receipts_line_uid JOIN po_line pol ON pol.po_line_uid=vl.po_line_uid JOIN inv_mast im ON im.inv_mast_uid=pol.inv_mast_uid
), demand AS (
 SELECT l.sample_name,l.complete_po_line_flag,l.inv_mast_uid,l.item_id,l.qty_received,
        demand=SUM(CASE WHEN COALESCE(ol.complete,'N')='N' AND COALESCE(oh.rma_flag,'N')='N' THEN CASE WHEN COALESCE(ol.qty_ordered,0)-COALESCE(ol.qty_allocated,0)-COALESCE(ol.qty_on_pick_tickets,0)-COALESCE(ol.qty_invoiced,0)>0 THEN COALESCE(ol.qty_ordered,0)-COALESCE(ol.qty_allocated,0)-COALESCE(ol.qty_on_pick_tickets,0)-COALESCE(ol.qty_invoiced,0) ELSE 0 END ELSE 0 END),
        avail=MAX(COALESCE(il.qty_on_hand,0)-COALESCE(il.qty_allocated,0))
 FROM lines l LEFT JOIN oe_line ol ON ol.inv_mast_uid=l.inv_mast_uid AND ol.ship_loc_id=@Loc LEFT JOIN oe_hdr oh ON oh.order_no=ol.order_no LEFT JOIN p21_view_inv_loc il ON il.inv_mast_uid=l.inv_mast_uid AND il.location_id=@Loc
 GROUP BY l.sample_name,l.complete_po_line_flag,l.inv_mast_uid,l.item_id,l.qty_received
)
SELECT result_set='gap_by_complete_po_line_flag', sample_name, complete_po_line_flag, line_count=CONVERT(varchar(50),COUNT(*)), receipt_qty=CONVERT(varchar(50),SUM(qty_received)), items_with_demand=CONVERT(varchar(50),SUM(CASE WHEN demand>0 THEN 1 ELSE 0 END)), items_with_avail=CONVERT(varchar(50),SUM(CASE WHEN avail>0 THEN 1 ELSE 0 END)), items_with_both=CONVERT(varchar(50),SUM(CASE WHEN demand>0 AND avail>0 THEN 1 ELSE 0 END))
FROM demand GROUP BY sample_name,complete_po_line_flag ORDER BY sample_name,complete_po_line_flag;
